import React, { useState } from 'react';
import axios from 'axios';
import { Upload, Wand2, Download, Loader2 } from 'lucide-react';
import { Button } from './ui/button';
import { Card } from './ui/card';

const presetStyles = [
  '日系手账风，柔和配色，纸张纹理',
  '科技感风格，蓝青色霓虹，高对比',
  '卡通插画风，明亮活泼，圆角元素',
  '极简风格，留白充足，清爽配色',
  '复古海报风，低饱和，颗粒质感',
  '像素游戏风，8-bit 配色与边框'
];

const StyleGenerator = () => {
  const [selectedFile, setSelectedFile] = useState(null);
  const [previewUrl, setPreviewUrl] = useState(null);
  const [stylePrompt, setStylePrompt] = useState(presetStyles[0]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);

  const handleFileSelect = (event) => {
    const file = event.target.files[0];
    if (!file) {
      return;
    }

    setSelectedFile(file);
    setPreviewUrl(URL.createObjectURL(file));
    setResult(null);
    setError(null);
  };

  const handleGenerate = async () => {
    if (!selectedFile) {
      setError('请先上传一张课表图片');
      return;
    }

    if (!stylePrompt.trim()) {
      setError('请输入想要的风格描述');
      return;
    }

    setIsGenerating(true);
    setError(null);

    const formData = new FormData();
    formData.append('image', selectedFile);
    formData.append('style', stylePrompt.trim());

    try {
      const response = await axios.post('/api/generate-style', formData, {
        headers: {
          'Content-Type': 'multipart/form-data'
        }
      });

      setResult(response.data);
    } catch (err) {
      console.error('生成失败:', err);
      setError(err.response?.data?.error || '生成失败，请重试');
    } finally {
      setIsGenerating(false);
    }
  };

  const handleDownload = () => {
    if (!result?.styledImage) {
      return;
    }

    const link = document.createElement('a');
    link.href = result.styledImage;
    link.download = `styled-schedule-${Date.now()}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const applyPresetStyle = (preset) => {
    setStylePrompt(preset);
    setError(null);
  };

  return (
    <div className="style-generator">
      <Card className="p-6">
        <h2 className="text-2xl font-bold mb-6">课表风格生成器</h2>

        <div className="space-y-6">
          <div>
            <label className="block text-sm font-medium mb-2">上传课表图片</label>
            <div className="border-2 border-dashed border-gray-300 rounded-lg p-8 text-center hover:border-gray-400 transition-colors">
              <input
                type="file"
                id="image-upload"
                accept="image/*"
                onChange={handleFileSelect}
                className="hidden"
              />
              <label
                htmlFor="image-upload"
                className="cursor-pointer flex flex-col items-center"
              >
                <Upload className="w-12 h-12 text-gray-400 mb-2" />
                <span className="text-sm text-gray-600">
                  点击上传课表图片
                </span>
              </label>
            </div>
          </div>

          {previewUrl && (
            <div>
              <label className="block text-sm font-medium mb-2">原始图片</label>
              <img
                src={previewUrl}
                alt="课表预览"
                className="max-w-full h-auto rounded-lg border"
              />
            </div>
          )}

          <div>
            <label className="block text-sm font-medium mb-2">风格描述</label>
            <textarea
              value={stylePrompt}
              onChange={(event) => setStylePrompt(event.target.value)}
              rows={4}
              className="w-full p-3 border rounded-lg resize-y"
              placeholder="例如：奶油色手账风，保留课表排版，加入胶带贴纸和手写标题感"
            />
            <p className="text-sm text-gray-500 mt-2">
              输入你想要的视觉风格，系统会尽量保持课程内容、时间、位置和表格结构不变。
            </p>
          </div>

          <div>
            <label className="block text-sm font-medium mb-2">快捷示例</label>
            <div className="flex flex-wrap gap-2">
              {presetStyles.map((preset) => (
                <button
                  key={preset}
                  type="button"
                  onClick={() => applyPresetStyle(preset)}
                  className="px-3 py-2 text-sm border rounded-full hover:bg-gray-50 transition-colors"
                >
                  {preset}
                </button>
              ))}
            </div>
          </div>

          <Button
            onClick={handleGenerate}
            disabled={!selectedFile || isGenerating}
            className="w-full"
          >
            {isGenerating ? (
              <>
                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                正在生成...
              </>
            ) : (
              <>
                <Wand2 className="w-4 h-4 mr-2" />
                生成风格化课表
              </>
            )}
          </Button>

          {error && (
            <div className="text-red-500 text-sm bg-red-50 p-3 rounded-lg">
              {error}
            </div>
          )}

          {result && (
            <div className="space-y-4">
              <h3 className="text-lg font-semibold">生成结果</h3>
              <img
                src={result.styledImage}
                alt="风格化课表"
                className="max-w-full h-auto rounded-lg border"
              />
              <Button onClick={handleDownload} className="w-full">
                <Download className="w-4 h-4 mr-2" />
                下载图片
              </Button>
            </div>
          )}
        </div>
      </Card>
    </div>
  );
};

export default StyleGenerator;
